        feedback_type = $4, notes = $5, updated_at = NOW()
      RETURNING *
    `, [req.user.id, candidate_id, job_id || null, feedback_type, notes || null]);

    // Feed into OmniScore: good_fit = +5 behavior points, not_fit = -3
    try {
      const points = feedback_type === 'good_fit' ? 5 : -2;
