      screening: { label: 'Screening', color: 'purple', order: 1 },
      interviewed: { label: 'Interviewed', color: 'cyan', order: 2 },
      offered: { label: 'Offered', color: 'emerald', order: 3 },
      hired: { label: 'Hired', color: 'green', order: 4 },
